MODULE.markerIds = MODULE.markerIds or {}
MODULE.running = false
MODULE.nextIndex = 1
MODULE.created = 0
MODULE.failed = 0

local function log(message)
  if env and env.info then
    env.info("[OMW-TOWNS-MARKERS] " .. tostring(message))
  end
end

local function markerText(index, point)
  local text = string.format("%04d | %s", index, point.name)
  if MODULE.config.includeCoordinatesInText then
    text = text .. string.format("\nN %.6f  E %.6f", point.latitude, point.longitude)
  end
  if MODULE.config.includeSourceLineInText then
    text = text .. string.format("\ntowns.lua Zeile %d", point.sourceLine)
  end
  return text
end

function MODULE.RemoveAll()
  local removed = 0
  for _, markerId in ipairs(MODULE.markerIds) do
    local ok = pcall(trigger.action.removeMark, markerId)
    if ok then removed = removed + 1 end
  end
  MODULE.markerIds = {}
  MODULE.running = false
  MODULE.nextIndex = 1
  MODULE.created = 0
  MODULE.failed = 0
  log(string.format("%d Marker entfernt.", removed))
end

local function createBatch(_, now)
  local total = #MODULE.points
  local lastIndex = math.min(MODULE.nextIndex + MODULE.config.batchSize - 1, total)

  while MODULE.nextIndex <= lastIndex do
    local index = MODULE.nextIndex
    local entry = MODULE.points[index]
    local markerId = MODULE.config.markerBaseId + index

    local okPoint, point = pcall(coord.LLtoLO, entry.latitude, entry.longitude, 0)
    if okPoint and type(point) == "table" and point.x and point.z then
      if land and land.getHeight then
        local okHeight, height = pcall(land.getHeight, { x = point.x, y = point.z })
        if okHeight and type(height) == "number" then point.y = height end
      end

      local okMark, markError = pcall(
        trigger.action.markToAll,
        markerId,
        markerText(index, entry),
        point,
        MODULE.config.readOnly,
        ""
      )

      if okMark then
        MODULE.markerIds[#MODULE.markerIds + 1] = markerId
        MODULE.created = MODULE.created + 1
      else
        MODULE.failed = MODULE.failed + 1
        log(string.format("Marker %d (%s) fehlgeschlagen: %s", index, entry.name, tostring(markError)))
      end
    else
      MODULE.failed = MODULE.failed + 1
      log(string.format("Koordinatenumrechnung %d (%s) fehlgeschlagen: %s", index, entry.name, tostring(point)))
    end

    MODULE.nextIndex = MODULE.nextIndex + 1
  end

  if MODULE.nextIndex <= total then
    return now + MODULE.config.batchInterval
  end

  MODULE.running = false
  local summary = string.format(
    "TOWNS-Marker fertig: %d von %d erstellt, %d Fehler.",
    MODULE.created, total, MODULE.failed
  log(summary)
  if trigger and trigger.action and trigger.action.outText then
    trigger.action.outText(summary, 15)
  end
  return nil
end

function MODULE.AddAll()
  if MODULE.running then
    log("Markererzeugung laeuft bereits.")
    return
  end

  MODULE.RemoveAll()
  MODULE.running = true
  MODULE.nextIndex = 1
  MODULE.created = 0
  MODULE.failed = 0

  local total = #MODULE.points
  log(string.format("Starte %d Marker aus der eingebetteten towns.lua-Tabelle.", total))
  if trigger and trigger.action and trigger.action.outText then
    trigger.action.outText(string.format("Erzeuge %d TOWNS-Marker ...", total), 10)
  end

  timer.scheduleFunction(createBatch, nil, timer.getTime() + MODULE.config.startDelay)
end

MODULE.AddAll()
